#ifndef AC_CORE_MODEL_ACNET_HPP
#define AC_CORE_MODEL_ACNET_HPP

#include <algorithm>
#include <cstddef>

#include "ACCoreExport.hpp" // Generated by CMake

namespace ac::core::model
{
    class ACNet;
}

class ac::core::model::ACNet
{
public:
    enum class Variant
    {
        GAN,
        HDN0,
        HDN1,
        HDN2,
        HDN3
    };

public:
    AC_CORE_EXPORT ACNet(Variant v) noexcept;

public:
    // length in numbers
    static constexpr int kernelLength() noexcept { return 8 * 9 + 8 * 8 * 9 * 8 + 8 * 4; }
    static constexpr int kernelLength(const int layer) noexcept { return (layer == 0) ? 8 * 9 : ((layer > 0 && layer < 9) ? 8 * 8 * 9 : ((layer == 9) ? 8 * 4 : 0)); }
    static constexpr int biasLength() noexcept { return 8 * 9; }
    static constexpr int biasLength(const int layer) noexcept { return (layer >= 0 && layer < 9) ? 8 : 0; }
    static constexpr int alphaLength() noexcept { return 0; }
    static constexpr int alphaLength(const int /*layer*/) noexcept { return 0; }
    // size in bytes
    static constexpr std::size_t kernelSize() noexcept { return kernelLength() * sizeof(float); }
    static constexpr std::size_t kernelSize(const int layer) noexcept { return kernelLength(layer) * sizeof(float); }
    static constexpr std::size_t biasSize() noexcept { return biasLength() * sizeof(float); }
    static constexpr std::size_t biasSize(const int layer) noexcept { return biasLength(layer) * sizeof(float); }
    static constexpr std::size_t alphaSize() noexcept { return alphaLength() * sizeof(float); }
    static constexpr std::size_t alphaSize(const int layer) noexcept { return alphaLength(layer) * sizeof(float); }

    static constexpr int kernels() noexcept { return 10; }
    static constexpr int biases() noexcept { return 9; }
    static constexpr int alphas() noexcept { return 0; }

    static constexpr int kernelIndex(const int layer) noexcept { return std::clamp(layer, 0, kernels() - 1); }
    static constexpr int biasIndex(const int layer) noexcept { return std::clamp(layer, 0, biases() - 1); }
    static constexpr int alphaIndex(const int /*layer*/) noexcept { return 0; }

    static constexpr int kernelLayer(const int idx) noexcept { return std::clamp(idx, 0, kernels() - 1); }
    static constexpr int biasLayer(const int idx) noexcept { return std::clamp(idx, 0, biases() - 1); }
    static constexpr int alphaLayer(const int /*idx*/) noexcept { return 0; }

    static constexpr int kernelOffset(const int layer) noexcept
    {
        int offset = 0;
        for(int i = 0; i < layer; i++)
            offset += kernelLength(i);
        return offset;
    }
    static constexpr int biasOffset(const int layer) noexcept
    {
        int offset = 0;
        for(int i = 0; i < layer; i++)
            offset += biasLength(i);
        return offset;
    }
    static constexpr int alphaOffset(const int /*layer*/) noexcept { return 0; }

    const float* kernel(const int layer = 0) const noexcept { return kptr + kernelOffset(layer); }
    const float* bias(const int layer = 0) const noexcept { return bptr + biasOffset(layer); }
    static constexpr const float* alpha(const int layer = 0) noexcept { return nullptr; }

private:
    const float* kptr;
    const float* bptr;
};

#endif
